// Node: "Redact PII & Build Error Record"
// Truncate and redact the failing payload before it is persisted anywhere:
// email addresses, phone-like numbers, and card-like digit runs are masked.
const err = $input.first().json;

function redact(text) {
  return String(text || '')
    .replace(/[\w.+-]+@[\w-]+\.[\w.]+/g, '[EMAIL_REDACTED]')
    .replace(/\b(?:\d[ -]?){13,19}\b/g, '[CARD_REDACTED]')
    .replace(/\+?\d[\d ()-]{8,}\d/g, '[PHONE_REDACTED]');
}

const execution = err.execution || {};
const lastNodeExecuted = execution.lastNodeExecuted || 'unknown';
const message = err.execution?.error?.message || err.trigger?.error?.message || 'Unknown error';

// Severity: transient (retryable upstream) vs persistent
const transient = /429|timeout|ETIMEDOUT|ECONNRESET|rate.?limit|503/i.test(message);

return [{ json: {
  workflow_name: err.workflow?.name || 'unknown',
  failed_node: lastNodeExecuted,
  error_message: redact(message).slice(0, 1000),
  payload_snapshot: redact(JSON.stringify(execution.lastNodeExecuted ? (execution.data || {}) : {})).slice(0, 2000),
  execution_id: execution.id || null,
  execution_url: execution.url || null,
  severity: transient ? 'transient' : 'persistent',
  timestamp: new Date().toISOString(),
}}];

